  // Attach global handlers once per page load
  if (!window._commentNoLeadingSpaceInit) {
    window._commentNoLeadingSpaceInit = true;

    // 1) Prevent typing a leading space
    document.addEventListener('keydown', function (e) {
      var t = e.target;
      if (!t) return;

      var name = t.getAttribute('name');
      if (name !== 'comment') return;

      // Space key?
      var isSpace =
        e.key === ' ' ||
        e.code === 'Space' ||
        e.keyCode === 32;

      if (!isSpace) return;

      var value = t.value || '';
      var caret = t.selectionStart || 0;

      // Text before caret
      var before = value.slice(0, caret);

      // If everything before caret is spaces (or empty), block the space
      if (/^\s*$/.test(before)) {
        e.preventDefault();
      }
    });

    // 2) Always trim leading spaces as user types / pastes
    document.addEventListener('input', function (e) {
      var t = e.target;
      if (!t) return;

      var name = t.getAttribute('name');
      if (name !== 'comment') return;

      var v = t.value || '';
      var trimmedLeft = v.replace(/^\s+/, ''); // remove leading spaces only

      if (trimmedLeft !== v) {
        var diff = v.length - trimmedLeft.length;
        t.value = trimmedLeft;

        // Try to keep caret position sensible
        try {
          var pos = (t.selectionStart || 0) - diff;
          if (pos < 0) pos = 0;
          t.setSelectionRange(pos, pos);
        } catch (err) {
          // ignore selection errors
        }
      }

      // Keep PM screen data in sync
      if (typeof data !== 'undefined') {
        data.comment = t.value;
      }
    });
  }

  // Initial value when screen loads (also without leading spaces)
  if (typeof data !== 'undefined' && data.comment != null) {
    return String(data.comment).replace(/^\s+/, '');
  }

  return '';
})()

