// This calc runs on the Select List whose variable is `status` (inside the Loop).
// 1) Default on first render
if (status === undefined || status === null || String(status).trim() === '') {
  status = 'OK';
}

// 2) Normalize any legacy/alternate texts the user might choose/paste
const v = String(status).trim().toUpperCase();

if (v === 'CHECKED AND OKAY' || v === 'CHECKED & OKAY' || v === 'OK' || v === 'GOOD') {
  status = 'OK';
} else if (v === 'NEEDS ATTENTION' || v === 'NEEDS_ATTENTION' || v === 'ISSUE' || v === 'NOT OK') {
  status = 'NEEDS_ATTENTION';
} else if (v === 'N/A' || v === 'NA' || v === 'NOT APPLICABLE') {
  status = 'NA';
} else if (!['OK','NEEDS_ATTENTION','NA'].includes(v)) {
  // Fallback safety: anything unexpected becomes OK
  status = 'OK';
}

// --- Guard: run only when the checklist array exists ---
if (!Array.isArray(checklist)) {
  // Ensure flags are safely initialized so the gateway doesn't break
  hasIssues   = false;
  issuesOnly  = [];
  issuesCount = 0;
  return;
}

// --- Require a comment for any item marked NEEDS_ATTENTION ---
for (let i = 0; i < checklist.length; i++) {
  const r = checklist[i];
  if (r && r.status === 'NEEDS_ATTENTION') {
    const c = (r.comment || '').trim();
    if (!c) {
      // Stop submission and point the user to the exact row
      throw new Error(`Please add a comment for “${r.label}”.`);
    }
  }
}

// --- Set flags used by the XOR gateway ---
hasIssues   = checklist.some(r => r && r.status === 'NEEDS_ATTENTION');
issuesOnly  = checklist.filter(r => r && r.status === 'NEEDS_ATTENTION');
issuesCount = issuesOnly.length;

