    color: #2b9bc7;
}

.md-stepper-horizontal .md-step .md-step-bar-left,
.md-stepper-horizontal .md-step .md-step-bar-right {
    position: absolute;
    top: 25px;
    height: 1px;
    border-top: 1px solid #DDDDDD;
}

.md-stepper-horizontal .md-step .md-step-bar-right {
    right: 0;
    left: 50%;
    margin-left: 20px;
}

.md-stepper-horizontal .md-step .md-step-bar-left {
    left: 0;
    right: 50%;
    margin-right: 20px;
}

/* =========================================================
   RADIO OPTION CARDS – fully clickable options
   ========================================================= */
.form-group > div > form .form-check {
    position: relative;
    margin-bottom: 10px;

    border: 1px solid #d5d9df;
    border-radius: 2px;
    background: #fff;
    overflow: hidden;

    transition: border-color 0.2s ease, box-shadow 0.2s ease, background-color 0.2s ease;
    cursor: pointer;
}

.form-group > div > form .form-check:hover {
    border-color: #0f7dd6;
    background-color: #f7faff;
}

/* label fills the entire card */
.form-group > div > form .form-check-label {
    display: block;
    padding: 10px 14px 10px 24px;
    line-height: 1;
    max-width: 100%;
    cursor: pointer;
    margin-bottom: 0;
    margin-left: 0; /* override global offset inside cards */
}

/* radio inside card */
.form-group > div > form .form-check-input {
    position: absolute;
    top: 50%;
    left: 16px;
    transform: translateY(-50%);
    margin: 0;

    width: 18px;
    height: 18px;
    border-width: 2px;
    flex-shrink: 0;
    accent-color: #005a8b;
    background-color: transparent !important;
    box-shadow: none !important;
    outline: none !important;
    border-radius: 50%;
}

/* highlight card when selected */
.form-group > div > form .form-check:has(.form-check-input:checked) {
    border-color: #0f7dd6;
    background-color: #f0f7ff;
    box-shadow: 0 0 0 2px rgba(15, 125, 214, 0.25);
}

.form-group > div > form .form-check:has(.form-check-input:checked) .form-check-label {
    font-weight: 600;
    color: #0b3c5d;
}

/* keep focus styles on card, not radio */
.form-group > div > form .form-check-input:checked {
    background-color: transparent !important;
    box-shadow: none !important;
}

.form-group > div > form .form-check-input:focus,
.form-group > div > form .form-check-input:focus-visible {
    outline: none !important;
    box-shadow: none !important;
}

/* =========================================================
   FILE UPLOAD & SUBMIT BUTTON
   ========================================================= */
[selector='file_upload'] button {
    border-radius: 20px;
    font-size: 16px;
}

/* first file_upload label */
[selector='file_upload']:first-of-type {
    font-weight: normal;
}

/* generic submit button (centered & full width) */
[selector='SubmitBtn'] {
    text-align: center;
    margin-top: 60px;
    margin-bottom: 30px;
}

[selector='SubmitBtn'] button {
    width: 100%;
}

/* =========================================================
   MULTISELECT / SELECT-LIKE CONTROLS
   ========================================================= */
.multiselect__content-wrapper {
    top: 100% !important;
    bottom: auto !important;
    margin-top: 6px;
    border: 2px solid #0f7dd6 !important;
    border-radius: 8px !important;
    background: #fff !important;
    box-shadow: 0 6px 14px rgba(0, 0, 0, 0.15) !important;
    z-index: 9999;
}

.multiselect .multiselect__tags {
    border-radius: 8px;
}



/* =========================================================
   NAV TABS (tab-nav) — clean horizontal pill radio group
   ========================================================= */
[selector='tab-nav'] {
    /* this is the form-group wrapper */
    margin: 16px 0 10px !important;
}

/* make the inner form the flex container */
[selector='tab-nav'] form {
    display: inline-flex;
    align-items: center;
    gap: 0;                 /* no gap between pills */

    padding: 3px;
    background: #f1f5f9;
    border-radius: 999px;
    border: 1px solid #d0d7e2;
}

/* RESET global "card" radio styles just for this group */
[selector='tab-nav'] .form-check {
    position: static !important;
    margin: 0 !important;
    padding: 0 !important;

    border: none !important;
    border-radius: 0 !important;
    background: transparent !important;
    box-shadow: none !important;
    overflow: visible !important;

    display: inline-flex !important;
    align-items: center;
    cursor: default !important;
}

/* hide native radio */
[selector='tab-nav'] .form-check-input {
    display: none !important;
}

/* pill buttons */
[selector='tab-nav'] .form-check-label {
    display: inline-flex;
    align-items: center;
    justify-content: center;

    padding: 6px 20px;
    min-width: 120px;

    border-radius: 999px;
    border: none;
    background: transparent;
    color: #1d4a7a;
    font: 600 14px/1.4 "Inter", "Segoe UI", Roboto, Arial, sans-serif;
    cursor: pointer;

    margin: 0 !important;  /* cancel global margin-left */
    transition: background-color 0.18s ease, color 0.18s ease,
                box-shadow 0.18s ease, transform 0.12s ease;
}

[selector='tab-nav'] .form-check-label:hover {
    background: #e2ecf8;
    transform: translateY(-1px);
}

/* ACTIVE STATE – solid pill */
[selector='tab-nav'] .form-check-input:checked + .form-check-label {
    background: #1d4ed8;          /* active blue */
    color: #ffffff !important;
    box-shadow: 0 2px 6px rgba(37, 99, 235, 0.45);
    transform: translateY(-1px);
}






/* =========================================================
   CHECKLIST RADIOS (checkItemRadio) — pill style menu
   ========================================================= */
[selector='checkItemRadio'] {
    display: flex;
    flex-direction: row;
    gap: 12px;
    flex-wrap: wrap;
}

[selector='checkItemRadio'] .form-check {
    display: inline-flex;
    align-items: center;
    margin: 0 10px 10px 0;
    padding: 0;
}

[selector='checkItemRadio'] .form-check-input {
    position: absolute;
    opacity: 0;
    pointer-events: none;
}

[selector='checkItemRadio'] .form-check-label {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 160px;
    padding: 10px 24px;

    border-radius: 999px;                /* full pill */
    background: #ffffff;
    color: #0b1a2b;
    border: 1px solid #d6dce5;
    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.08);

    font: 600 15px/1.4 "Inter", "Segoe UI", Roboto, Arial, sans-serif;
    transition: all 0.2s ease;
    cursor: pointer;
}

[selector='checkItemRadio'] .form-check-label:hover {
    background: #f1f5f9;
    border-color: #cbd5e1;
    box-shadow: 0 4px 10px rgba(0, 0, 0, 0.12);
    transform: translateY(-1px);
}

/* active pill menu: darker + more “selected” */
[selector='checkItemRadio'] .form-check-input:checked + .form-check-label {
    background: #1d4ed8;                               /* darker blue */
    color: #ffffff !important;
    border-color: #1d4ed8;
    box-shadow:
        0 0 0 2px rgba(37, 99, 235, 0.45),
        0 6px 14px rgba(15, 23, 42, 0.25);            /* strong pop */
    transform: translateY(-1px);
}
